require_once __DIR__.'/helpers.php';if(logged_in())redirect('dashboard.php');$pageTitle='Daftar';$errors=[];
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$name=trim($_POST['name']??'');$email=trim($_POST['email']??'');$password=$_POST['password']??'';if(strlen($name)<3)$errors[]='Nama minimal 3 karakter.';if(!filter_var($email,FILTER_VALIDATE_EMAIL))$errors[]='Email tidak valid.';if(strlen($password)<8)$errors[]='Password minimal 8 karakter.';if(!$errors){try{$stmt=db()->prepare('INSERT INTO users(name,email,password,role) VALUES(?,?,?,?)');$stmt->execute([$name,$email,password_hash($password,PASSWORD_DEFAULT),'donor']);$_SESSION['user']=['id'=>(int)db()->lastInsertId(),'name'=>$name,'email'=>$email,'role'=>'donor'];flash('success','Akun berhasil dibuat.');redirect('dashboard.php');}catch(PDOException $e){$errors[]='Email sudah digunakan.';}}}
include __DIR__.'/partials/header.php';?>
<section class="auth-page container"><div class="glass auth-card"><span class="eyebrow">Bergabung</span><h1>Buat akun donatur</h1><p>Simpan riwayat dan pantau seluruh donasi dalam satu tempat.</p><?php if($errors):?><div class="alert error"><ul><?php foreach($errors as $er):?><li><?=e($er)?></li><?php endforeach;?></ul></div><?php endif;?><form method="post" class="stack-form"><?=csrf_field()?><label>Nama lengkap<input name="name" value="<?=old('name')?>" required></label><label>Email<input type="email" name="email" value="<?=old('email')?>" required></label><label>Password<input type="password" name="password" minlength="8" required></label><button class="btn primary wide">Daftar</button></form><p>Sudah punya akun? <a href="<?=url('login.php')?>">Masuk</a></p></div></section>
